"""rAIdio.bot — Python interpreter customizations for the embedded ComfyUI.

Loaded automatically by `site.py` at every Python interpreter startup
in `python_embeded/`. Applies to:

  1. The ComfyUI main process (python.exe -s ComfyUI/main.py …)
  2. Any subprocess spawned by ComfyUI (e.g. RVC's training Popen)
  3. Any `multiprocessing.Process` child those subprocesses fork
     (Windows uses 'spawn', so each child is a fresh interpreter
     that re-runs site.py and re-loads this file).

That third level is the reason this file exists. ComfyUI-RVC's
`rvc/infer/modules/train/train.py:129` calls
`torch.distributed.init_process_group(backend="gloo", ...)`
unconditionally, even on single-GPU setups where there is exactly
one rank. Gloo's rendezvous would open a TCP socket on loopback
(127.0.0.1) and resolve the local hostname — neither needed by us,
both surfaced as user-visible "this is making network calls"
behaviour. We ship single-GPU only; no rank coordination is
required.

This customization makes `init_process_group` a no-op when the
would-be world_size is 1, leaves it alone otherwise (preserves
correctness for any multi-GPU code paths a future user might
exercise), and pins the gloo backend to loopback as a defence in
depth.

Licensed under GPL-3.0 to match the GPL-3.0 PyTorch ecosystem
this patches into.
Source: https://github.com/rAIdio-bot/rAIdio-nodes
"""

import logging
import os


def _disable_gloo_dist_for_single_rank() -> None:
    """Replace torch.distributed.init_process_group with a no-op for
    single-rank invocations. Multi-rank calls fall through to the real
    function untouched."""
    try:
        import torch.distributed as dist  # type: ignore[import-not-found]
    except Exception:
        # Torch not importable in this interpreter (very unusual; the
        # ComfyUI Python embed always has torch). Nothing to do.
        return

    real_init = dist.init_process_group

    if getattr(real_init, "_raidio_dist_patched", False):
        return

    def _is_single_rank(world_size, store) -> bool:
        if world_size is not None:
            try:
                return int(world_size) <= 1
            except (TypeError, ValueError):
                return False
        # No explicit world_size — fall back to the env var torchrun /
        # torch.distributed.launch sets. Default = 1 (no DDP).
        return int(os.environ.get("WORLD_SIZE", "1")) <= 1

    def _patched_init_process_group(
        backend=None,
        init_method=None,
        timeout=None,
        world_size=None,
        rank=None,
        store=None,
        group_name="",
        pg_options=None,
        device_id=None,
    ):
        if _is_single_rank(world_size, store):
            logging.warning(
                "[rAIdio dist-noop] init_process_group call intercepted "
                "(world_size=1, no rank coordination needed); skipping. "
                "backend=%r init_method=%r",
                backend,
                init_method,
            )
            return None
        # Multi-rank — let the real call through. Belt-and-suspenders
        # below sets GLOO_SOCKET_IFNAME so the bind stays on loopback.
        return real_init(
            backend=backend,
            init_method=init_method,
            timeout=timeout,
            world_size=world_size,
            rank=rank,
            store=store,
            group_name=group_name,
            pg_options=pg_options,
            device_id=device_id,
        )

    _patched_init_process_group._raidio_dist_patched = True  # type: ignore[attr-defined]
    dist.init_process_group = _patched_init_process_group


def _pin_dist_to_loopback() -> None:
    """If anything *does* slip past the no-op (or a future feature
    legitimately needs DDP on multi-GPU users), force the gloo / NCCL
    rendezvous onto loopback so no traffic ever leaves the machine."""
    os.environ.setdefault("GLOO_SOCKET_IFNAME", "lo")
    os.environ.setdefault("MASTER_ADDR", "127.0.0.1")
    os.environ.setdefault("MASTER_PORT", "29500")


_disable_gloo_dist_for_single_rank()
_pin_dist_to_loopback()
logging.info("[rAIdio usercustomize] dist no-op + loopback pinning applied")
